#include <iostream>

void resetToZero(int& num) {
    num = 0;
}

int main() {
    int val1 = 42;
    std::cout << "Initial val1: " << val1 << std::endl;
    resetToZero(val1);
    std::cout << "After reset val1: " << val1 << std::endl;

    int val2 = -5;
    std::cout << "Initial val2: " << val2 << std::endl;
    resetToZero(val2);
    std::cout << "After reset val2: " << val2 << std::endl;
    return 0;
}
